import { h, clear } from '../utils/h';
/**
 * The Settings tab: content-editor-facing controls (per-rule enable/disable,
 * WCAG level/version, theme, live, engine, ignored selectors). Changes persist
 * to {@link ProjectStore} (shared with the project) and apply live via
 * `onChange`.
 */
export class SettingsPanel {
    constructor(root, registry, opts, store, t, onChange) {
        this.root = root;
        this.registry = registry;
        this.opts = opts;
        this.store = store;
        this.t = t;
        this.onChange = onChange;
        this.build();
    }
    emit(patch) {
        this.store.setSettings(patch);
        this.onChange(patch);
    }
    select(label, value, options, onSet) {
        const sel = h('select', {
            class: 'gjs-as-select',
            attrs: { 'aria-label': label },
            on: { change: () => onSet(sel.value) },
        });
        for (const [val, text] of options)
            sel.appendChild(h('option', { attrs: { value: val }, text }));
        sel.value = value;
        return h('div', { class: 'gjs-as-field' }, [h('label', { text: label }), sel]);
    }
    checkbox(label, checked, onSet) {
        const input = h('input', { attrs: { type: 'checkbox' }, on: { change: () => onSet(input.checked) } });
        input.checked = checked;
        return h('label', { class: 'gjs-as-check' }, [input, h('span', { text: label })]);
    }
    build() {
        const form = h('div', { class: 'gjs-as-form' });
        form.appendChild(h('div', { class: 'gjs-as-counter', text: this.t('settings.intro') }));
        // WCAG level / version
        form.appendChild(this.select(this.t('settings.wcagLevel'), this.opts.wcagLevel, [['AA', 'AA'], ['AAA', 'AAA']], (v) => this.emit({ wcagLevel: v })));
        form.appendChild(this.select(this.t('settings.wcagVersion'), this.opts.wcagVersion, [['2.0', '2.0'], ['2.1', '2.1'], ['2.2', '2.2']], (v) => this.emit({ wcagVersion: v })));
        form.appendChild(this.select(this.t('settings.theme'), this.opts.theme, [['dark', 'dark'], ['light', 'light'], ['auto', 'auto']], (v) => this.emit({ theme: v })));
        form.appendChild(this.select(this.t('settings.engine'), this.opts.engine, [['builtin', 'builtin'], ['axe', 'axe']], (v) => this.emit({ engine: v })));
        form.appendChild(h('div', { class: 'gjs-as-field' }, [
            this.checkbox(this.t('settings.live'), this.opts.live, (v) => this.emit({ live: v })),
        ]));
        // Ignore selectors
        const ta = h('textarea', {
            attrs: { 'aria-label': this.t('settings.ignoreSelectors') },
            on: {
                change: () => {
                    const list = ta.value
                        .split('\n')
                        .map((s) => s.trim())
                        .filter(Boolean);
                    this.emit({ ignoreSelectors: list });
                },
            },
        });
        ta.value = this.opts.ignoreSelectors.join('\n');
        form.appendChild(h('div', { class: 'gjs-as-field' }, [h('label', { text: this.t('settings.ignoreSelectors') }), ta]));
        // Rules enable/disable
        form.appendChild(h('div', { class: 'gjs-as-section-title', text: this.t('settings.rules') }));
        const rulesBox = h('div', { class: 'gjs-as-rules' });
        for (const rule of this.registry.list()) {
            rulesBox.appendChild(h('div', { class: 'gjs-as-field' }, [
                this.checkbox(rule.id, rule.enabled !== false, (v) => {
                    if (v)
                        this.registry.enable(rule.id);
                    else
                        this.registry.disable(rule.id);
                    this.emit({ disabledRules: this.registry.list().filter((r) => r.enabled === false).map((r) => r.id) });
                }),
            ]));
        }
        form.appendChild(rulesBox);
        clear(this.root);
        this.root.appendChild(form);
    }
    /** Rebuild (e.g. after settings load). */
    refresh() {
        this.build();
    }
}
