/** Trailing-edge debounce. */
export function debounce(fn, wait) {
    let timer;
    const wrapped = (...args) => {
        if (timer)
            clearTimeout(timer);
        timer = setTimeout(() => {
            timer = undefined;
            fn(...args);
        }, wait);
    };
    wrapped.cancel = () => {
        if (timer)
            clearTimeout(timer);
        timer = undefined;
    };
    return wrapped;
}
